            // Existing 500K docs use "Discriminator"; direct SQL queries reference c.Discriminator.
            // Keep old name so existing documents and SQL queries continue to work.
            entity.HasDiscriminator<string>("Discriminator");

            // BREAKING CHANGE 2 (High): id no longer contains discriminator prefix.
            // Old format: "Product|123", new default: "123".
            // Keep old format so existing documents remain reachable.
            entity.HasDiscriminatorInJsonId();

            // BREAKING CHANGE 3 (High): Key property now maps directly to JSON "id".
            // Old behavior used a shadow __id property; the int Id was stored separately.
            // Restore shadow id so the int Id property stays in the document as "Id".
            entity.HasShadowId();

            // BREAKING CHANGE 4 (Low): HasIndex now throws (was silently ignored).
            // Cosmos indexes all properties by default; manage via Azure Portal.
            // REMOVED: entity.HasIndex(p => p.Sku);
        });
    }
}
